    public function __construct($city = "") {
        // Код метода 1
		$this->regions = json_decode($this->regions_json_string,true);
		$this->pr = json_decode($this->pr_json_string,true);
		$this->rf_deliv = json_decode($this->rf_deliv_json_string,true);
		$this->sup_ec = json_decode($this->sup_ec_json_string,true);
		$this->city = $city;
    }


	public function calc($weight) {
		
		$regId = 21;	//иркутск
		$toField = 'usa';

		if ($this->city!='') foreach($this->regions as $region) {
			if ($region['value']==$this->city) $regId=$region['id'];
		}
		//print_r($regId);
		//$del; //Доставка по России
        //$total; //Общая стоимость
        $cons = 0; //Стоимость консолидации  
        $box = 0; //Стоимость коробки    
        $pack = 0; //Стоимость упаковки		
		$curs = 1;
		$curs2 = 90.163;
		$maxWeights = array(
			'post' => 20,
			'ems' => 23,
			'emsplus' => 31.5,
			'ems_new' => 31.5,
			'dhl' => 20,
			'super' => 20,
			'priority' => 31.5,
			'priority' => 30,
			'balt_post' => 31
		);
		
		
		
		$zone = $this->regions[$regId]["zone"]; //Номер тарифной зоны 
		$storageDelPrice2 = $this->sup_ec[$toField][0]['price'];
		foreach ($this->sup_ec[$toField] as $i => $delivery) {
			$storageDelPrice2 = $delivery['price'];
			if (floatval($delivery['weight']) >= $weight) {
				break;
			}
		}
		
		//print_r($curs." ".$weight." ".$storageDelPrice2." ".$zone);
		
		if($curs>0 && $weight>0 && $storageDelPrice2>0 && $zone>=0) {
		
			$del = $this->sup_ec[$toField][0]['price'];    
			foreach($this->sup_ec[$toField] as $i=>$v) {
				$del = $this->sup_ec[$toField][$i]['price'];
				if(floatval($this->sup_ec[$toField][$i]["weight"])>=$weight) break;
			}
			$del = $del*$curs;
			$cost =  $del; 			
			
		}
		 
		return $cost;
	}
	
	
	
	
